async function bindleftCommonSearchdropdown(instance) {
    var vm = instance;
    
    // Load Client Options
    try {
        // TODO: Replace with actual API call
        // const clientResponse = await locateBillingService.GetClientList();
        // vm.leftSearchFields.find(f => f.fieldName === 'ClientName').listOptions = clientResponse.data;
    } catch (error) {
        console.error('Error loading clients:', error);
    }
    
    // Load State Options
    try {
        const url = `countryId=223&includeCandaState=true`;
        const response = await locateBillingService.GetStateList(url);
        if (response.data) {
             const stateOptions = response.data.items.map(item => ({
                 description: null,
                 displayValue: item.displayValue,
                 groupText: null,
                 groupValue: null,
                 metaData: null,
                 text: item.displayValue,
                 value: item.code
            }));
            vm.leftSearchFields.find(f => f.fieldName === 'State').listOptions = stateOptions;
        }
    } catch (error) {
        console.error('Error loading states:', error);
    }
    
    // Load Flag Options
    try {
        // TODO: Replace with actual API call
        const flagResponse = await locateBillingService.GetFlagType();
        if (flagResponse.data) {
            const flagOptions = flagResponse.data.map(item => ({
                 description: null,
                 displayValue: item.SERVICE_NAME,
                 groupText: null,
                 groupValue: null,
                 metaData: null,
                 text: item.SERVICE_NAME,
                 value: item.SERVICE_ID
            }));
            vm.leftSearchFields.find(f => f.fieldName === 'Flag').listOptions = flagOptions;
        }
    } catch (error) {
        console.error('Error loading flags:', error);
    }   

        // LOAD BILLER OPTION GetBillerList
        try {
            const url = `reqFrom=all&moduleName=Billing`;
            const BillerResponse = (await DataService.GetBillerList(url));
            const BillerResponses=JSON.parse(BillerResponse.data.result)
            if (BillerResponses) {
             
                const BillerOptions = BillerResponses.map(item => ({
                    description: item.EMAIL_ID || null,
                    displayValue: item.USERNAME,
                    groupText: item.DEPARTMENT_NAME || null,
                    groupValue: null,
                    metaData: item,
                    text: item.USERNAME,     
                    value: item.USERID       
                }));

                const billerField = vm.leftSearchFields.find(
                    f => f.fieldName === 'Biller'
                );

                if (billerField) {
                    billerField.listOptions = BillerOptions;
                }
            }
        } catch (error) {
            console.error('Error loading Biller:', error);
        }

    
    // Load Cost Center Options
    try {
        // TODO: Replace with actual API call
        const costCenterResponse = await locateBillingService.GetCostCenters();
        if (costCenterResponse.data) {
            const CostCenterOptions = costCenterResponse.data.map(item => ({
                 description: null,
                 displayValue: item.TEXT,
                 groupText: null,
                 groupValue: null,
                 metaData: null,
                 text: item.TEXT,
                 value: item.VALUE
            }));
            vm.leftSearchFields.find(f => f.fieldName === 'CostCenters').listOptions = CostCenterOptions;
        }
    } catch (error) {
        console.error('Error loading cost centers:', error);
    }
    
    // Load Utility Options (depends on Client selection)
    // This will be handled dynamically when client is selected
    
    // Load Biller Options
    try {
        // TODO: Replace with actual API call
        // const billerResponse = await DataService.GetAssignedBillerByCompanyId();
        // vm.leftSearchFields.find(f => f.fieldName === 'Biller').listOptions = billerResponse.data;
    } catch (error) {
        console.error('Error loading billers:', error);
    }
}

