<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <tg-list 
            ref="tgList" 
            :listType="['List']" 
            :IsShowAction="true" 
            :showCheckBox="false" 
            ModuleName="BillingValidationData"
            SubModuleCode="BilledUnbilledRecords" 
            IdentityColumn="COLUMN_ID" 
            :HeaderText="$t('BilledUnbilledRecords')" 
            :ListData="ListingData"
            :HeaderData="Headers" 
            :widgets="widgets" 
            :HeaderButtons="Buttons" 
            :TotalRecords="TotalRecords"
            :RenderRowActionMethod="renderActions" 
            :ListDataCallBackFunction="FetchBilledUnbilledRecords" 
            :SortExp="SortExp"
            :SortBy="SortBy" 
            :NorecordfoundText="$t('NoRecordfound')" 
            v-on:PagerButtonClick="pagerMethod"
            v-on:HeaderButtonClick="commonHeaderButtonClick" 
            v-on:SortdataButtonClick="sortdata"
            v-on:LeftsearchButtonClick="leftCommonSearch"
            v-on:ActionButtonClick="actionButtonClick"
            :SearchFields="leftSearchFields"
            SearchPosition="top"
            :LegendArray="LegendArray"
            :key="refreshKey"
            :CurrentPageNumber="PageNumber"
            :isShowHeaderText="true"
            :routeInfo="$router"
        >
            <template v-slot:slotdata="{ data }">
                <template v-if="data.column.COLUMN_NAME == 'COST'">
                    <span class="textalignright paddingright5">{{ $n(data.row.COST, "currency", $getLocaleByCurrency(CurrencyCode)) }}</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'DATEOFINV'">
                    <span v-if="data.row.DATEOFINV || data.row.DATEOFINV" :title="data.row.DATEOFINV || data.row.DATEOFINV">
                      {{ $options.filters.formatDate(data.row.DATEOFINV) }}     
                    </span>
                    <span v-else>--</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'DATEOFWORK'">
                    <span v-if="data.row.DATEOFWORK || data.row.DATEOFWORK" :title="data.row.DATEOFWORK || data.row.DATEOFWORK">
                       {{ $options.filters.formatDate(data.row.DATEOFWORK) }}  
                    </span>
                    <span v-else>--</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'FREQUENCY'">
                    <span>{{ getFrequencyName(data.row.FREQUENCY) }}</span>
                </template>
            </template>
        </tg-list>
          <EditInvoiceLineItem v-if="IsEditInvoiceItem" :columnId="columnId" :ClientId="ClientId" :TicketNumber="TicketNumber" :lineItemId="lineItemId" :IsProcessed="IsProcessed" :IsAdd="IsAdd" :ticketType="ticketType" :isTicketMannual="isTicketMannual" :dateOfInvoice="WorkDateFrom" :dateOfInvoiceTO="WorkDateTo"></EditInvoiceLineItem>
           <transition name="modal">
            <div class="my-popups"  v-if="IsViewTicket">
                <loader :is-visible="isLoading"></loader>
                   <div class="modal my-popups right fade d-block" :class="{ show: isShown }">
                    <div role="document" class="modal-dialog" style="max-width: 1300px !important;">
                        <div class="modal-content">
                            <div class="modal-header">
                                <h4 class="modal-title">{{ $t('TicketImage') }}</h4>

                                <button type="button" class="close" v-on:click="CloseTemplate">
                                    <em class="fa fa-times" aria-hidden="true"></em>
                                </button>

                            </div>
                            <div class="modal-body">
                                <div class="col-md-12">
                                    <div class="listing" v-if="TicketContent">
                                        <div
                                            v-html="TicketContent"
                                            class="col-12 p-0"
                                            style="min-height: 440px;white-space: pre-line;">
                                        </div>
                                    </div>
                                    <div v-else class="listing text-danger text-center border-0">
                                        {{ $t("NorecordfoundText") }}
                                    </div>

                                </div>
                            </div>

                            <div class="modal-footer">
                                <button @click="CloseTemplate" class="btn btn-danger">
                                    <em class="fa fa-times pr-2" aria-hidden="true"></em> {{ $t('Cancel') }}
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </transition>
    </section>
</template>

<script>
import { locateBillingService } from "../../../services/locateBillingService";
import DataService from "../../../services/DataService";
import Schema from "./BilledUnbilledRecordsSchema";
import EditInvoiceLineItem from "../../BillingValidationData/components/EditInvoiceLineItem.vue";

export default {
    name: "BilledUnbilledRecords",
    components: { EditInvoiceLineItem},
    data() {
        return {
            isLoading: false,
            PageSize: 10,
            PageNumber: 1,
            isPaged: 1,
            TotalPages: 0,
            widgets: [],
            LegendArray: [],
            SortBy: '',
            SortExp: '',
            CurrentPage: 1,
            TotalRecords: 0,
            ListingData: [],
            Buttons: Schema.buttons,
            leftSearchFields: Schema.leftsearchSchema,
            listActions: Schema.listActions,
            Headers: Schema.headerSchema,
            searchCondition: "",
            frequencyList: [],
            IsEditInvoiceItem: '',
            columnId:'',
            lineItemId:'',
            ClientId: '',
            IsProcessed: 1,
            IsAdd: false,
            ticketType: 'N',
            isTicketMannual: 'N',
            TicketNumber: '',
            IsViewTicket: false,
            TicketContent: '',
            selectedId:'',
            CurrencyCode: 'USD',
            LegendArray: [
            {
            class: "legend-Progress colorboxsquare",
            text: this.$t('Sent invoices cannot be edited.'),
            }
            ],
            additionalClass:'',
            refreshKey: 0,
            isShown:false,
            WorkDateFrom:'',
            WorkDateTo:'',
            isSupervisor:false

        }
    },
    mounted() {
        this.$nextTick(() => {
            setTimeout(() => {
                this.isShown = true;  // adds .show ? triggers transform transition
            }, 50);
        });
    },
    created: async function () {
        var vm = this;
        var UserDateFormat= vm.GetUserInfo.DateFormat == ""? 'MM/DD/YYYY' : vm.GetUserInfo.DateFormat;
         if (vm.leftSearchFields?.length > 0) {
            vm.leftSearchFields.find(f => f.fieldName === 'Work_Date').format= UserDateFormat;
            vm.leftSearchFields.find(f => f.fieldName === 'ProcessDate').format= UserDateFormat
            vm.leftSearchFields.find(f => f.fieldName === 'ClientName').onChange= vm.onSelectionChange;
            vm.leftSearchFields.find(f => f.fieldName === 'Work_Date').onChange= vm.setTimerDate;
            vm.leftSearchFields.find(f => f.fieldName === 'ProcessDate').onChange= vm.setProcessTimerDate;
            vm.leftSearchFields[0].onChange = vm.onSelectionChange;
            vm.leftSearchFields[1].onChange = vm.onSelectionUtilityChange;
        }
        vm.Headers.forEach(element => {
            element.DISPLAY_NAME = vm.$t(element.DISPLAY_NAME);
        });
        await vm.BindSupervisor();
        await vm.GetEmailConfigurationSetting(); 
        Schema.bindleftCommonSearchdropdown(this);  
        this.PageNumber = 1;
        await vm.fetchclientlist();

        vm.CurrencyCode = vm.GetUserInfo.Currency.replace(/[()]/g, '');
        //vm.FetchBilledUnbilledRecords();
    },
    methods: {
        setTimerDate(x) {
            this.applySecondDate(x);
        },

        setProcessTimerDate(x) {
            this.applySecondDate(x);
        },
        applySecondDate(x) {
            var vm = this;
            x.datePickerConfig.maxDate = '';

            const today = new Date();
            today.setHours(0, 0, 0, 0);

            const parseDate = (val) => {
                if (val instanceof Date && !isNaN(val.getTime())) {
                    const d = new Date(val);
                    d.setHours(0, 0, 0, 0);
                    return d;
                }

                if (typeof val === 'string' && val) {
                    const parts = val.split(/[\/\-]/);
                    if (parts.length === 3) {
                        const month = parseInt(parts[0], 10) - 1;
                        const day   = parseInt(parts[1], 10);
                        const year  = parseInt(parts[2], 10);

                        const d = new Date(year, month, day);
                        d.setHours(0, 0, 0, 0);
                        return isNaN(d.getTime()) ? null : d;
                    }
                }
                return null;
            };

            const valueDate  = parseDate(x.value);
            const secondDate = parseDate(x.secondValue);

            // ✅ If secondValue already exists
            if (secondDate) {
                if (valueDate && valueDate > secondDate) {
                    x.secondValue = vm.$options.filters.formatDate(valueDate);
                }else{
                    x.secondValue = vm.$options.filters.formatDate(secondDate);
                }
                // else → keep existing secondValue
                return;
            }

            // ✅ If secondValue does NOT exist yet
            if (valueDate && valueDate > today) {
                x.secondValue = vm.$options.filters.formatDate(valueDate);
            } else {
                x.secondValue = vm.$options.filters.formatDate(today);
            }
        },
        leftCommonSearch: function (value) {
            var vm=this;
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                if (value.searchConditionJson != '') {
                    this.searchCondition = value.searchConditionJson;
                } else {
                    this.searchCondition = value.searchCondition || "";
                }
            } else {
                this.searchCondition = "";
            }
            if (this.searchCondition) {
                this.searchCondition = this.searchCondition.replace(/WorkDate=([^&]+)/, function (_, val) {
                    let [from, to] = val.split("|");
                    if (from && !to) {
                        to = new Date().toISOString().split('T')[0];
                    }
                    vm.WorkDateFrom=from; vm.WorkDateTo= to;
                    return `WorkDateFrom=${from}&WorkDateTo=${to}`;
                });
                this.searchCondition = this.searchCondition.replace(/ProcessDate=([^&]+)/, function (_, val) {
                    let [from, to] = val.split("|");
                    if (from && !to) {
                        to = new Date().toISOString().split('T')[0];
                    }
                    return `ProcessDateFrom=${from}&ProcessDateTo=${to}`;
                });
            }
            if(value.searchCondition=='' && value.searchConditionJson==''){
                vm.ListingData = [];
                vm.TotalRecords = 0;
                vm.PageNumber = 1;
                vm.refreshKey += 1;
                vm.leftSearchFields[3].value="B"
            }else{
                this.FetchBilledUnbilledRecords();
            }
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                switch (action.title) {
                    case 'TicketImage':
                        action.isVisible = true;
                        break;
                    case 'Edit':
                        // Disable edit if STATUS_CODE is "CLBSND"
                        if (row.STATUS_CODE === "CLBSND") {
                            action.isVisible = true;
                            action.isDisabled= true;
                        } else {
                            action.isVisible = true;
                            action.isDisabled= false;
                        }
                        break;
                    default: {
                        action.isVisible = true;
                    }
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        CloseTemplate: function () {
            var vueObj = this;
            vueObj.IsViewTicket = false;
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchBilledUnbilledRecords();
        },
        actionButtonClick: function (callbackfunction, item) {
            switch (callbackfunction) {
                case 'ViewTicketImage':
                    this.viewTicketImage(item);
                    break;
                case 'EditRecord':
                    this.editRecord(item);
                    break;
            }
        },
        commonHeaderButtonClick: function (event) {
            // Handle header button clicks if needed
        },
        sortdata: function (sortBy) {
            this.SortBy = sortBy;
            if (this.SortExp == "") {
                this.SortExp = "ASC";
            } else if (this.SortExp == "ASC") {
                this.SortExp = "DESC";
            } else {
                this.SortExp = "ASC";
            }
            this.FetchBilledUnbilledRecords();
        },
        FetchBilledUnbilledRecords: async function () {
            var vm = this;
            vm.isLoading = true;
            var url = `pageSize=${vm.PageSize}&pageNum=${vm.PageNumber}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}`;
            
            // Add search condition if available
            if (vm.searchCondition) {
                url += `&${vm.searchCondition}`;
            }
            vm.TotalRecords = 0;
            await locateBillingService.GetBilledUnbilledRecords(url).then((response) => {
                vm.isLoading = false;
                if(response.data.result){
                    vm.ListingData=JSON.parse(response.data.result)
                }
                if (vm.ListingData  && vm.ListingData.length > 0) {
                    vm.ListingData.forEach((item) => {
                        if (item.DATEOFINV) {
                            item.DATEOFINV = new Date(item.DATEOFINV);
                        }
                        if (item.DATEOFWORK) {
                            item.DATEOFWORK = new Date(item.DATEOFWORK);
                        }
                    });
                    vm.ListingData.forEach((row)=>{
                    row.additionalClass = '';
                    if (row.STATUS_CODE =="CLBSND") {
                       row.additionalClass='low-bar';
                    }
                    });  
                    vm.TotalRecords = vm.ListingData[0].TOTAL_RECORDS || vm.ListingData[0].TOTALRECORDS || 0;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                    vm.CurrentPage = vm.PageNumber;
                } else {
                    vm.ListingData = [];
                    vm.TotalRecords = 0;
                }
            }).catch((error) => {
                vm.isLoading = false;
                vm.ListingData = [];
                vm.TotalRecords = 0;
                console.error('Error fetching flag records:', error);
            });
            
        },
        formatCurrency(value) {
            if (!value && value !== 0) return '0.00';
            return parseFloat(value).toFixed(2);
        },
        getFrequencyName(frequencyValue) {
            if (!frequencyValue) return '';
            const frequency = this.frequencyList.find(f => f.Value == frequencyValue || f.value == frequencyValue);
            return frequency ? (frequency.Name || frequency.name || '') : frequencyValue;
        },
        viewTicketImage: function(item) {
            var vm =this;
            var privilegeParams = `controller=BilledUnbilledRecords&action=ViewTicketImage`;
            DataService.CheckPrivilege(privilegeParams).then(function (response) {
            if (response.data) {
            vm.TicketNumber= item.TICKETNUMBER;
            vm.TransmissionId= item.TRANSMISSION_ID;
            vm.IsViewTicket= !vm.IsViewTicket;
            var url = `TicketNumber=${vm.TicketNumber}&TransmissionId=${vm.TransmissionId}`
            locateBillingService.ViewTicketImage(url).then((response) => {
                if (response.data.length>0) {
                    vm.TicketContent = response.data[0].RAW_IMAGE;
                }
            });
            }
            else {
                vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                return false;
            }
            });
        },
        editRecord(item) {
            var vm =this;
            var privilegeParams = `controller=BilledUnbilledRecords&action=EditInvoiceLineItem`;
            DataService.CheckPrivilege(privilegeParams).then(function (response) {
            if (response.data) {
            vm.columnId= item.TRAN_NO;
            vm.lineItemId=item.COLUMN_ID;
            vm.ClientId= item.CLIENT_ID;
            vm.TicketNumber= item.TICKETNUMBER;
            vm.IsEditInvoiceItem = !vm.IsEditInvoiceItem;
            }
            else {
                vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                return false;
            }
            });
        },
        fetchclientlist: function () {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOM`;
            locateBillingService.getClientList(url).then(response => {
                vm.isLoading = false;
                vm.clientList = response.data.items;
                vm.leftSearchFields.find(f => f.fieldName === 'ClientName').listOptions = vm.clientList;
                vm.groupedUtilities=vm.clientList;
            }).catch(error => {
                vm.isLoading = false;
                vm.clientList = []; 
                vm.leftSearchFields.find(f => f.fieldName === 'ClientName').listOptions = [];
                console.error('Error fetching client list:', error);
            }).finally(() => {
                vm.isLoading = false;
            });
        },
         onSelectionChange(value,x) {
        // Ensure value is an array for multiple mode
            var vm = this;
            //vm.isLoading = true;
            vm.selectedId=x;
            var url = `clientId=${x}&configId=&reqFrom=&clientIds=`;
            locateBillingService.getUtilityList(url).then(response => {
                //vm.isLoading = false;
                let SelectedUtilityList=[];
                    var UtilityList = response.data;
                    if (UtilityList != null) {
                        UtilityList.forEach(item => {
                            let obj = {
                                description: null,
                                displayValue: item.UTILITY_NAME,
                                groupText: null,
                                groupValue: null,
                                metaData: null,
                                text: item.UTILITY_NAME,
                                value: item.UTILITY_ID   
                            };
                            SelectedUtilityList.push(obj);
                        });
                        vm.leftSearchFields.find(f => f.fieldName === 'UtilityName').listOptions = SelectedUtilityList;
                    }
            }).catch(error => {
                //vm.isLoading = false;
                vm.SelectedUtilityList = []; 
                vm.leftSearchFields.find(f => f.fieldName === 'UtilityName').listOptions = [];
                vm.leftSearchFields.find(f => f.fieldName === 'Division').listOptions = '';
                vm.leftSearchFields.find(f => f.fieldName === 'UtilityName').value='';
                vm.leftSearchFields.find(f => f.fieldName === 'Division').value='';
            }).finally(() => {
                //vm.isLoading = false;
            });
        },
          BindSupervisor: async function () {
            debugger
            var vm = this;           
            await DataService.CheckIsSupervisor().then(response => {
                if (response.data) {                      
                    vm.isSupervisor=response.data;
                }
            });
        },

         async GetEmailConfigurationSetting() {
            debugger
            var vm = this;
            var params = `_CompanyId=${vm.GetUserInfo.CompanyId}&userId=${vm.GetUserInfo.ID}&moduleName=User&configkey=CanViewAllContractData`;
            await DataService.GetEmailConfigurationSetting(params)
                .then(response => {
                    if (response.data && response.data.length > 0)
                    {
                        if(response.data[0].CONFIG_DATA_VALUE.toLowerCase() === 'yes' || vm.GetUserInfo.UserType.toLowerCase()=='ca' || vm.isSupervisor){                           
                            Schema.bindleftCommonSearchdropdown(this,"BILLER");                      
                        } else {
                          vm.leftSearchFields = vm.leftSearchFields.filter(f => f.fieldName !== 'Biller');
                        }
                    }
                })
                .catch(err => {
                    console.log(err);
                });
        },

        onSelectionUtilityChange(value,x) {
            var vm = this;
            //vm.isLoading = true;
            let UtilityIds = x.map(i => `${i}`).join(",");
            var url = `clientId=${vm.selectedId}&utilityIds=${UtilityIds}`;
            locateBillingService.LoadClientDivisionList(url).then(response => {
               //vm.isLoading = false;
                let SelectedDivisionList=[];
                    var DivisionList = response.data;
                    if (DivisionList != null) {
                        DivisionList.forEach(item => {
                            let obj = {
                                description: null,
                                displayValue: item.NOTE,
                                groupText: null,
                                groupValue: null,
                                metaData: null,
                                text: item.NOTE,
                                value: item.ID   
                            };
                            SelectedDivisionList.push(obj);
                        });
                        vm.leftSearchFields.find(f => f.fieldName === 'Division').listOptions = SelectedDivisionList;
                        vm.leftSearchFields.find(f => f.fieldName === 'Division').value='';
                    }
            }).catch(error => {
                //vm.isLoading = false;
                vm.DivisionList = []; 
                vm.leftSearchFields.find(f => f.fieldName === 'Division').listOptions = [];
                vm.leftSearchFields.find(f => f.fieldName === 'Division').value='';
            }).finally(() => {
                //vm.isLoading = false;
            });
        },
    }
}
</script>

<style scoped>
.textalignright {
    text-align: right;
}
.paddingright5 {
    padding-right: 5px;
}
</style>
